#include <vector>
#include <string>
using namespace std;

class Solution {
public:
    vector<int> plusOne(const vector<int>& digits) {
        long long number = 0;
        for (int digit : digits) {
            number = number * 10 + digit;
        }
        number += 1;

        vector<int> result;
        while (number > 0) {
            result.push_back(number % 10);
            number /= 10;
        }
        reverse(result.begin(), result.end());
        return result;
    }
};

