package main

import (
	"fmt"
)

func plusOne(digits []int) []int {
	num := 0
	for _, digit := range digits {
		num = num*10 + digit
	}
	num++
	result := []int{}
	for num > 0 {
		result = append([]int{num % 10}, result...)
		num /= 10
	}
	if len(result) == 0 {
		return []int{0}
	}
	return result
}

func main() {
	fmt.Println(plusOne([]int{1, 2, 3})) // Output: [1, 2, 4]
	fmt.Println(plusOne([]int{9}))       // Output: [1, 0]
}

