    vector<int> plusOne(const vector<int>& digits) {
        vector<int> result = digits;
        int n = result.size();
        for (int i = n - 1; i >= 0; --i) {
            if (result[i] < 9) {
                result[i]++;
                return result;
            }
            result[i] = 0;
        }
        result.insert(result.begin(), 1);
        return result;
    }
